var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 네? 알파트릭스 재단에서 전학생이요?","JPN":"はい？　アルファトリックス財団から転入生？","ENG":"What? A transfer student from the Alphatrix Foundation?","TWN":"什麼？從阿爾法崔克斯財團來的轉學生嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 그렇습니다. 감찰 한 번 없던 알파트릭스 측에서 갑자기 전학생을 보낸다는군요.","JPN":"そうです。これまで監察をしたこともなかったアルファトリックス側から、急に転入生を送ると連絡がありました。","ENG":"Yes. Alphatrix, who has never submitted to an inspection, is suddenly sending us a transfer.","TWN":"沒錯，阿爾法崔克斯沒事突然送個轉學生過來。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 우리 같은 일반 학교가 이렇게 번듯한 시설을 차려서 운영되고 있는 건 어디까지나 알파트릭스의 후원 덕분입니다.","JPN":"我々のような一般学校がここまで立派な施設を持って運営できているのは、アルファトリックスの支援があってこそです。","ENG":"As you know, thanks to Alphatrix, our school has been operating with the good facilities.","TWN":"不過像我們這種普通的學校，都是因為有阿爾法崔克斯的贊助，才可以有這些設施與建設。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 그러니 각별히 신경 좀 써줘요, 선생. 내 말 무슨 뜻인지 알겠죠?","JPN":"なので特別に気にかけてあげてください。私の言葉の意味、わかりますね？","ENG":"So be nice when the transfer student comes. Do you understand me?","TWN":"所以你要多關照一下，聽懂我的意思嗎，老師？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 자, 오늘은 새 전학생이 왔어.","JPN":"さ、今日は新しく転入生が来ました。","ENG":"We have a new student today.","TWN":"大家，這是今天來的轉學生。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 나와서 간단하게 자기 소개해볼까?","JPN":"前に来て、簡単に自己紹介してみようか。","ENG":"Would you please introduce yourself?","TWN":"你可以出來跟大家自我介紹嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 대침식전을 선도하는 알파트릭스 이노베이션에서 지정사수를 맡고 있는 김초원이야.","JPN":"対侵食戦を先導するアルファトリックス・イノベーションで選抜射手を担当している、スズキ・ナオです。","ENG":"Hi, I’m Kim Chowon, designated marksman of Alphatrix Innovation, the leading anti-Corruption team.","TWN":"我叫金初源，在阿爾法崔克斯改革帶領的侵蝕戰中負責射手的位置。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 김 씨라고 부르든, 초원이라고 부르든 상관없어.","JPN":"スズキでも、ナオでもどちらでも好きに呼んでください。","ENG":"You can either call me Kim or Chowon, I don’t really care.","TWN":"隨便大家要叫我小金，或叫我初源都可以。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 알파트릭스의 이미지 메이킹 목적으로 위장 입학한 것뿐이니까. 친해지려고 시도하지 않아도 돼.","JPN":"アルファトリックスのイメージアップのための偽装入学なので、別に仲良くなろうとする必要はありません。","ENG":"I’m only here to promote Alphatrix, so you don’t have to be nice to me.","TWN":"我是因為要替阿爾法崔克斯打造企業形象，才會假裝過來上學，可以不用跟我做朋友沒關係。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 브리핑은 이상, 질문은?","JPN":"自己紹介は以上です。質問はありますか？","ENG":"That's it for the briefing. Any questions?","TWN":"以上，有問題嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":" 쟤 뭐야? 총을 가지고 있어. 머리가 살짝 이상한 거 아냐?","JPN":"何？　あの子。　銃を持ってる。ちょっと頭おかしいんじゃない？","ENG":"She has a gun. Is she crazy?","TWN":"她是怎樣？來上學還帶槍？頭殼壞掉喔？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":" 등굣길에 외제차에서 내리던 그 애 맞지? 부잣집 딸인가?","JPN":"外車で登校してきた子だよね？　どっかの金持ちの娘なのかな？","ENG":"I saw her getting out of a super nice car in the morning. Is she rich?","TWN":"她就是從進口車下來的女生吧？她是有錢人家的女兒喔？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":" 단순한 부자가 아니야. 외제차로 배웅해주던 사람 못 봤어? 알파트릭스 회장 손녀였잖아!","JPN":"ただの金持ちじゃないよ。一緒に外車に乗っていた人は、アルファトリックスの会長の孫娘だったんだって！","ENG":"She’s not just rich. Didn’t you see who brought her here? It was the granddaughter of the Alphatrix CEO!","TWN":"她可不是一般的有錢人家，你沒看到送她來的人嗎？根本是阿爾法崔克斯會長的孫女吧！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 저기, 초원아? 왜 학교에 총을 들고 온 거니?","JPN":"えっと、ナオさん？　どうして学校に銃を持ってきたの？","ENG":"Um, Chowon? Why did you bring a gun here?","TWN":"初源？來學校為什麼要帶槍呢？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 안심하세요. 학교에선 이건 대인 진압용 고무탄이니까요, 선생님.","JPN":"安心してください、先生。これは、対人鎮圧用のゴム弾ですから。","ENG":"Don’t worry, teacher. This is only a rubber bullet gun.","TWN":"老師請放心，在學校我只會用鎮壓人類的橡皮子彈而已。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 급소만 안 맞으면 이승 하직은 하지 않아요. 하고 싶어질 만큼 아프겠지만요.","JPN":"急所さえ当たらなければ、あの世に行くことはありません。死にたくなるほど痛いとは思いますけどね。","ENG":"It won’t kill you unless you’re hit on your vital points. It must be deathly painful, though.","TWN":"只要沒有命中要害，是不會有性命危險的，頂多是痛到生不如死而已。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 그, 그래도 별 이유도 없으면서 학교에서 무기를 휴대하는 건 곤란해.","JPN":"で、でも特別な理由もなく学校で武器を携帯するのは困るわ。","ENG":"Still, you should not bring a weapon to school without any reason.","TWN":"可是…又沒什麼特殊原因需求，帶槍來學校還是不太好吧？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 이해했습니다. 명목이 있으면 괜찮다는 거군요.","JPN":"わかりました。理由があればいいのですね？","ENG":"Oh, so you’re saying that I need a reason to bring a weapon here?","TWN":"原來如此，是需要一個名義嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 이 학교에도 자경단이나 보안팀이 있다면 지원하고 싶은데요.","JPN":"この学校にも自警団やセキュリティチームがあるのなら、志願したいのですが。","ENG":"If that’s the case, I would like to volunteer for the school security team.","TWN":"那請問學校有自衛隊或是安全組嗎？我自願加入。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 보, 보안팀…? 그런 건 없지만 그나마 비슷한 거라면…….","JPN":"セ、セキュリティチーム……？　それはないけど、似たようなものなら……","ENG":"A security team...? We don’t have such a thing, but...","TWN":"安…安全組…？學校沒有安全組，硬要說的話……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 하아… 하아… 하아…","JPN":"はあ……はあ……はあ……","ENG":"*Pant*","TWN":"呼呼…呼呼…呼呼…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 쳇, 도시관리국 놈들. 하필 거기서 매복하고 있을 줄이야.","JPN":"くそっ、都市管理局のやつらめ。よりによって、あそこに潜伏していたとは。","ENG":"Damn that City Management. I didn’t expect them to ambush me there.","TWN":"嗟，那些城市管理局的傢伙，偏偏給我埋伏在那裡！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 블랙 네트워크에서 비싸게 주고 구한 슈트가 아니었으면 위험할 뻔했어.","JPN":"ブラックネットワークで高い金払って用意したこのスーツがなければ危ないところだった。","ENG":"It could have been dangerous if it wasn’t for the suit I got from the Dark Network.","TWN":"要不是我這件花了不少錢在黑色網路上弄到的強化服，我早就栽在他們手裡。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 응? 저 건물은…… 학교인가?","JPN":"うん？　あの建物は……学校か？","ENG":"Is that... a school?","TWN":"嗯？那棟建築物是……學校？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 응, 그래. 초원아 무슨 일이야?","JPN":"はい、ナオさん。どうしたの？","ENG":"Yes, Chowon. What is it?","TWN":"嗯？初源你有什麼事嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 선생님, 하달해주신 임무를 모두 완수했습니다.","JPN":"先生、任務をすべて完了しました。","ENG":"Teacher, I’ve accomplished all the missions you assigned me.","TWN":"老師，你交辦的任務已經全部處理完畢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 이, 임무? 임무라니 무슨…","JPN":"に、任務？　なんの話かしら……","ENG":"Um, missions? What missions?","TWN":"任…任務？什麼任務…"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 설마 좀 전에 맡겼던 선도부 일을 말하는 거야?","JPN":"まさかさっきお願いした風紀委員の仕事のこと？","ENG":"Do you mean the student council thing?","TWN":"你是指之前提過的學生會的事嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 네, 선생님의 지시대로라면 선도부의 임무는 교칙을 어기는 자들을 응당 처벌하는 것.","JPN":"はい。先生のお話を聞いたところ、風紀委員の任務は校則を破った者に相応の処罰を与えることだと考えました。","ENG":"Yes. I know the student council is supposed to punish those who violate school regulations.","TWN":"是，照老師的吩咐，就是要懲處那些違反校規的人。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 하지만 저 혼자서 모든 걸 감시하기엔 무리가 있으니, 교칙 위반에 취약한 시설들을 보강하고 오는 길입니다.","JPN":"ですが私一人で全校生徒を監視するには無理があったので、校則違反に脆弱な箇所を補強してきました。","ENG":"But I can’t apprehend every one of them, so I’ve decided to improve school installations to prevent such occurrences.","TWN":"但光靠我一個人，要監視全校學生有困難，所以我將那些容易造成違反校規的設施進行強化後，現在來找老師報告。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 보, 보강이라니… 어떤 걸 바꿨다는 거니?","JPN":"ほ、補強って……？","ENG":"Okay... which installations did you improve?","TWN":"強…強化…？你動了哪些東西？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 첫번째 교칙. <color=#ffd34c>학교 담장을 넘지 말 것.</color>","JPN":"校則その一、<color=#ffd34c>学校の塀を越えるべからず。</color>","ENG":"First rule. <color=#ffd34c>Don’t climb over the wall.</color>","TWN":"校規第一條：<color=#ffd34c>不可穿越學校圍牆。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 담벽에 철조망을 설치했습니다만, 그럼에도 넘으려는 인원이 있다면, 따끔한 맛을 보게 되겠죠.","JPN":"塀の上に有刺鉄線を設置しましたが、それでも越えようとする人員がいた場合、ピリッと痛い目を見ることでしょう。","ENG":"So I added barbed wire to the wall. If someone tries to climb the wall, they will have a shocking experience.","TWN":"我已經在圍牆上設置鐵絲網，萬一還是有人堅持要穿越圍牆，那他就會感受到刺痛感。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 죽지 않을 정도로만요.","JPN":"死なない程度に。","ENG":"It won’t kill them though.","TWN":"但是不至於會死亡。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" …철조망? 따끔한 맛이라고?","JPN":"……有刺鉄線？　痛い目？","ENG":"Barbed wire? A shocking experience?","TWN":"…鐵絲網？刺痛感？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>…도시관리국에서 알려드립니다.</color>","JPN":"<color=#ffd34c>……都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>...This is an announcement from City Management.</color>","TWN":"<color=#ffd34c>…城市管理局通知。</color>"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>현재 수배 중인 무장 범죄자가 도주 중입니다. 도시관리국의 병력이 검거를 위해 추적하고 있으니, 시민 여러분은… </color>","JPN":"<color=#ffd34c>現在、手配中の武装犯罪者が逃走しています。都市管理局の兵力が検挙のため追跡しておりますので、市民の皆様におかれましては……</color>","ENG":"<color=#ffd34c>We have an armed criminal on the run. City Management is currently trying to apprehend the criminal...</color>","TWN":"<color=#ffd34c>目前有名通緝中的武裝罪犯正在逃亡，城市管理局已派出人力拘捕中，請各位市民…</color>"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 큭, 벌써 여기까지 쫓아왔나?","JPN":"くっ、もうここまで来やがったか。","ENG":"Damn, are they here already?","TWN":"可惡，已經追到這裡來了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 좋아. 일단 학교로 잠입한 뒤에 지원이 올 때까지 학생과 교직원을 인질로 농성하는 거야!","JPN":"よし、いったん学校に潜入して応援が来るまで、生徒や教師どもを人質にして立てこもろう！","ENG":"Okay, I’ll go to the school and take the schoolchildren hostage until my people come!","TWN":"好！在我的救兵來之前，我就先潛入學校，挾持學生和老師當人質！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 우선, 이 담장을…","JPN":"まずはこの塀を……","ENG":"Okay, let’s climb the wall first...","TWN":"我要先翻過圍牆…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 뭐야? 요즘이 어떤 시대인데 학교 담장에 철조망을 둘러 뒀어?","JPN":"なんだ？　塀に有刺鉄線だなんて、随分と時代遅れな学校だな？","ENG":"Huh? Barbed wire? What kind of school is this?","TWN":"這是怎樣？現在都什麼時代了，還有人會在學校圍牆上設置鐵絲網？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 슈트가 제값을 하는군. 하마터면 찔릴 뻔했잖아.","JPN":"スーツがあって本当によかった。下手すりゃ刺されるとこだった。","ENG":"I’m glad I had this suit. I could have cut myself.","TWN":"強化服果然貴得有價值，我剛差點被刺到。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 어, 어라… 잠깐 이건…!?","JPN":"お、おっと……これは……！？","ENG":"Huh? Wait, what is this...?!","TWN":"嗯…？這是…？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 으, 으아아아악!!","JPN":"う、うわああああっ！！","ENG":"Argh!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 대체 이 학교 뭐야? 학교에 왜 전기 철조망이 쳐져 있는 거야!?","JPN":"いったいなんなんだ、この学校は！　なんで学校に電気柵があるんだ！？","ENG":"What the heck? Is it electric barbed wire?","TWN":"這間學校是怎樣？鐵絲網竟然有通電？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" …제길, 왜 내가 이 나이에 학교 담장 따위로 쩔쩔매고 있는 거람.","JPN":"……くそ、この年で学校の塀ごときに手こずってる場合か。","ENG":"Damn it, what the heck am I doing here?","TWN":"…該死的，活到這把年紀，竟然還被區區一個學校圍牆搞得這麼狼狽！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":"우회해서 돌아가야겠어.","JPN":"迂回して侵入しよう。","ENG":"I have to take another route.","TWN":"找別的路進去吧！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 좋아, 일단은 걸리지 않고 학교 후문으로 들어왔어.","JPN":"よし、ひとまずバレずに裏門から入ってこれた。","ENG":"Okay, now I’m in the school.","TWN":"很好！順利躲過大家的耳目從學校後門進來。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" …나야. 현재 도시관리국 내 일반학교에 숨어있다.","JPN":"……俺だ。現在、都市管理局内の一般学校に潜んでいる。","ENG":"It’s me. I’m hiding in a school within the City Management’s vicinity.","TWN":"…喂，是我，我現在躲在城市管理局內的一所普通學校。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 하지만 도시관리국 놈들이 나를 쫓고 있어.","JPN":"だが、都市管理局の連中に追われている状況だ。","ENG":"But City Management is on my tail.","TWN":"城市管理局的那些傢伙還在追捕我。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 농성으로 최대한 시간을 벌어보겠지만, 포위되는 것은 시간 문제야.","JPN":"立てこもってできるだけ時間を稼ぐつもりだが、包囲されるのは時間の問題だ。","ENG":"I’ll try to buy some time using hostages, but sooner or later they’ll come after me.","TWN":"我會挾持學校盡量拖延時間，但被包圍只是時間的問題。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 연막탄을 피워 이곳 위치를 알릴 테니, 이쪽으로 지원을 보내도록.","JPN":"煙幕でここの位置を伝えるから、応援をよこしてほしい。","ENG":"Send me some support, I’ll send up a smoke signal to let you know where I am.","TWN":"我會點燃煙霧彈告訴你們我的具體位置，趕快派人過來！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":"좋아. 이 정도면 내 신호인 줄 알겠지.","JPN":"できた。これなら俺からの信号だって伝わるだろう。","ENG":"Good. Now they’ll know where I am.","TWN":"OK！這樣應該就知道是我發出的訊號吧？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 으응? 방금 또 무슨 소리가…?","JPN":"んん？　なんだ、この音……？","ENG":"Huh? What was that sound?","TWN":"嗯？剛剛那又是什麼聲音…？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 두번째 교칙, <color=#ffd34c>교내에서는 흡연하지 말 것.</color>","JPN":"校則その二、<color=#ffd34c>校内で喫煙するべからず。</color>","ENG":"Second rule. <color=#ffd34c>No smoking in the school.</color>","TWN":"校規第二條：<color=#ffd34c>校內禁止吸菸。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 흡연 목적 외에 불을 피울 일은 없을 테니, 전 교사에 열원 감지 트랩을 설치해 뒀습니다.","JPN":"喫煙以外の目的で火をつけることは考えにくいので、校舎に熱源感知のトラップを仕掛けておきました。","ENG":"To punish those who smoke cigarettes in the school, I installed a number of heat traps.","TWN":"除了吸菸之外，應該不會有人在校內點火，所以我在全校的校舍安裝了熱偵測器。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 트랩이라니… 작동하면 무슨 일이 일어나는데?","JPN":"トラップって……引っかかったらどうなるの？","ENG":"Traps... what happens if they are triggered?","TWN":"熱偵測器…？啟動後會發生什麼事？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 맑은 공기의 소중함을 깨닫게 될 겁니다.","JPN":"澄んだ空気の大切さを思い知ることになるでしょう。","ENG":"They will learn how precious fresh air is.","TWN":"會了解到新鮮空氣的寶貴。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 크윽! 뭐가 어떻게 돌아가는 거야? 왜 학교에서 최루탄이 터지는 거냐고!","JPN":"くうっ！　なんなんだ、これは！　なんで学校に催涙弾があるんだよ！","ENG":"Argh! What’s going on? Why would they have tear gas bombs in a school?","TWN":"唔！怎麼這麼多煙？為什麼會在學校內引爆催淚彈啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" …콜록! 콜록 콜록!","JPN":"……ゲホッ！　ゲホッ、ゲホッ！","ENG":"*Cough*","TWN":"…咳咳！咳咳咳！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" …뭐지? 아까의 전기 충격으로 공기 순환 장치가 고장났나…?","JPN":"……なんだ？　さっきの電気ショックで空気循環装置が壊れたか……？","ENG":"Huh? Is the ventilation system broken?","TWN":"…是怎樣？剛剛的電擊導致空氣流通裝置壞掉了嗎…？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 이렇게 된 이상, 이판사판이야! 우선 교실로 들어가서 인질 확보를...!!","JPN":"こうなったら一か八かだ！　まずは教室に入って、人質を確保する……！！","ENG":"Damn, I have no other way! I have to take hostages first!","TWN":"既然如此！不管了啦！先衝進教室挾持人質…！！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L50_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 제, 젠장… 또 이번엔 무슨 소리야…?","JPN":"ち、ちくしょう……今度はまた何の音だ……？","ENG":"What... what was that...?","TWN":"該…該死…這又是什麼聲音啦…？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …그리고 세번째 교칙, <color=#ffd34c>복도에서 뛰지 말 것.</color>","JPN":"……そして校則その三、<color=#ffd34c>廊下を走るべからず。</color>","ENG":"Third rule. <color=#ffd34c>No running in the hall.</color>","TWN":"…然後校規第三條：<color=#ffd34c>不可在走廊上奔跑。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 이를 위해 각 층 복도에 움직임을 감지할 수 있는 적외선 센서를 설치했습니다.","JPN":"このため、各層の廊下に動きを感知する赤外線センサーを設置しました。","ENG":"So I installed infrared sensors on each floor.","TWN":"為了防止學生在走廊上奔跑，我在每層樓的走廊上安裝了可以偵測到移動的紅外線感應器。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 어… 달리면 어떻게 되는데?","JPN":"ええと、それは走ったらどうなるの？","ENG":"So... what happens if you run?","TWN":"喔…那奔跑的話會怎樣？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 시속 8km 이상으로 움직일 경우, 기폭장치가 작동합니다.","JPN":"時速8km以上のスピードを出した場合、起爆装置が作動します。","ENG":"If your running speed exceeds 8km/h, it will trigger an explosion.","TWN":"移動速度超過8km以上時，就會啟動雷管裝置。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 기폭… 뭐?","JPN":"きばく……？","ENG":"Trigger... a what?","TWN":"雷管…？？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 걸렸군요.","JPN":"引っかかりましたね。","ENG":"There.","TWN":"抓到了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 걸렸군요… 가 아니잖아! 친구들이 다쳤으면 어쩌려고 그래?","JPN":"引っかかりましたね……じゃないわよ！　友だちが怪我でもしたらどうするつもり！？","ENG":"What do you mean, \\"there\\"! What if your classmates are hurt!","TWN":"抓到了…重點不是這個吧！！萬一有人受傷怎麼辦？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 안심하세요. 모든 부비트랩은 대인 진압을 목적으로 화력을 조절했습니다.","JPN":"安心してください。すべてのトラップは対人鎮圧レベルに火力を調整してあります。","ENG":"Don’t worry. The traps will only suppress them, not kill them.","TWN":"老師請放心，因為目的只是要鎮壓壞人，所以我安排後的所有裝置都是有調整過火力的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 아니, 그게 아니라…!!","JPN":"そ、そうじゃなくて……！！","ENG":"You don’t understand...!","TWN":"就跟你說重點不是那個…！！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …엎드리세요!","JPN":"……伏せてください！","ENG":"Stay down!","TWN":"…趴下！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 다들 손 머리 위로 올리고 바닥에 넙죽 엎드려!","JPN":"全員、手を頭の上に置いて、床に伏せろ！","ENG":"Everyone hands up and stay down!","TWN":"所有人手舉高趴下！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" …누, 누구시죠? 학교에서 이런 짓을 벌이다니!","JPN":"……ど、どなたですか？　学校でこのようなことをするなんて！","ENG":"Who are you? This is a school, how could you...!","TWN":"…你…你是誰？竟然在學校做這種事！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 시끄러워!","JPN":"うるせぇ！","ENG":"Shut up!","TWN":"閉嘴！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 학교를 대체 어떤 녀석이 이따위로 설계했는지는 몰라도, 덕분에 내가 굉장히 화가 났다고.","JPN":"いったい誰が学校を設計したのかは知らんが、おかげさまで俺は今すごく機嫌が悪い。","ENG":"How could you call a place like this a school? This place really pisses me off!","TWN":"雖然我不知道到底是誰把學校弄成這樣的，但我現在很火大！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 그러니 아무도 움직이지 마! 그랬다간 이 교사를 쏴 버릴 테니까!","JPN":"だから誰も動くんじゃねぇぞ！　動いたらこの教師を撃ってやるからな！","ENG":"Nobody move! Or I’ll shoot her!","TWN":"全都不准動！誰敢亂動老師就會變成蜂窩！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 아, 알겠어요. 가만히 있으면 되잖아요.","JPN":"わ、わかりました。おとなしくします。","ENG":"Okay, I won’t do anything.","TWN":"知…知道了，不動就是了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 테러리스트인가요? 원하는 게 뭐죠?","JPN":"テロリストですか？　望みはなんです？","ENG":"Are you a terrorist? What do you want?","TWN":"你是恐怖份子嗎？你想要什麼？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 뭐, 뭐야? 학생이 총을 가지고 있다니. 당장 그거 버리지 못해!","JPN":"な、なんだ？　生徒が銃を持ってるなんて。今すぐそれを捨てろ！","ENG":"Huh? A student with a gun? Hey, put it down!","TWN":"什…什麼鬼？學生竟然帶著槍？給我把槍扔掉！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 두 손을 머리에 올린 상태로는 어렵겠는데요. 제 총은 멜빵끈과 이어져 있거든요.","JPN":"両手を上げている状態では難しいですね。私の銃はショルダーストラップと繋がっているので。","ENG":"I can’t with my hands up. This gun is tied to my suspenders, you see.","TWN":"在雙手舉高的狀態下有點困難，因為槍和背帶是連在一起的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 제가 그쪽으로 다가가면 당신이 제 멜빵끈 클립을 대신 풀 수 있지 않을까요?","JPN":"私がそっちに行けば、あなたがストラップのクリップを外せるんじゃないですか？","ENG":"Maybe you can untie the gun from my suspenders if you let me get closer to you.","TWN":"還是我過去你那裡，你幫我解開？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" …그렇군. 그럼 당장 이쪽으로 오도록 해. 네 녀석도 내 동료들이 올 때까지 인질이 돼줘야겠어.","JPN":"……そうだな。今すぐこっちに来い。お前も俺の仲間が来るまで人質になってもらうぞ。","ENG":"Okay, come here. I’m holding you all as hostages until my people come.","TWN":"…好吧，那你過來，在我的救兵到之前，你也要當我的人質！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 그러죠.","JPN":"いいですよ。","ENG":"Okay.","TWN":"沒問題。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 좋아. 그럼 그대로 끈을…","JPN":"よし、じゃあそのままストラップを……","ENG":"Now, let me untie the string...","TWN":"我看看，這要怎麼解…"},"stage":{"bg":"OFFICE_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 으윽?! 무슨 힘이…! 떨어지지 못해!","JPN":"うぐっ！？　なんて力だ……！　離せ！！","ENG":"Huh? You’re super strong...! Stay away from me!","TWN":"噢嗚？！力氣好大…鬆手！放手啊！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …테러리스트와 협상은 없습니다. 어린 애도 아는 상식이죠.","JPN":"……テロリストとは交渉しません。子どもでも分かる常識です。","ENG":"We do not negotiate with terrorists. It’s common sense.","TWN":"…不能跟恐怖份子談判。這不是連三歲小孩都知道的常識嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 블랙 타이드 슈트는 파워는 세지만, 관절부가 취약하죠.","JPN":"ブラックタイドスーツはパワーはありますが、関節部位が脆いのです。","ENG":"The Black Tide suit may be powerful, but its joints are weak.","TWN":"黑潮強化服雖然很強，但關節的部分很弱。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 아무리 카운터라고 해도 5분 이상 경부가 압박되면 의식을 유지하기 힘들 거예요.","JPN":"いくらカウンターとはいえ、5分以上頸部を圧迫されれば意識を保つのは難しいでしょう。","ENG":"You will lose consciousness if I strangle your neck for over five minutes, even if you are a Counter.","TWN":"就算是再怎麼厲害的制裁者，只要頸部受到壓迫超過5分鐘以上，就會失去意識。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 으아악! 이거 놔!! 놓으라고…!!","JPN":"あああっ！　離せ！！　離せっつってんだろ……！！","ENG":"Let me go! Let me go!","TWN":"呃啊啊！放開！給我放手…！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 쉽게 떨어지진 않을 겁니다. 자랑은 아니지만, 전 꽤 근육질이거든요.","JPN":"そう簡単にはいきませませんよ。自慢ではありませんが、私、結構筋肉質なので。","ENG":"I won’t. Not to brag, but I'm quite muscular.","TWN":"我不可能輕易鬆手的。我不是在炫耀，只是我的肌肉比較發達而已。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 이 녀석, 무슨 힘이… 카운터냐?","JPN":"こいつ、この力は……カウンターか？","ENG":"What are you... a Counter?","TWN":"這傢伙力氣未免…難道她是制裁者嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 하지만… 여긴… 일반학교일 텐데…….","JPN":"しかし……ここは……一般学校のはずでは……","ENG":"But... this is just an ordinary school...","TWN":"可是…這裡…不是普通學校嗎……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":"커헉…","JPN":"がはっ……","ENG":"Hurp...","TWN":"咳咳…"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":" 전학생이… 저 범죄자를 맨손으로 잡았어.","JPN":"転入生が……あの犯罪者を素手で捕まえた。","ENG":"The transfer student caught a criminal with bear hands.","TWN":"那個轉學生…徒手制裁歹徒欸！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":" 총을 들고 다녀서 이상한 애라고 생각했는데... 엄청 멋있어!","JPN":"銃を持ってるから変な子だと思ったのに……すごいかっこいい！","ENG":"I thought she was crazy with the gun and all... but she’s actually very cool!","TWN":"看她拿把槍到處跑，還以為她是怪咖咧…結果超帥的！！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 괜찮으세요, 선생님?","JPN":"大丈夫ですか？　先生。","ENG":"Are you alright, teacher?","TWN":"老師你沒事吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 으응? …아, 난 괜찮아. 고마워.","JPN":"え？　あ……私は大丈夫よ。ありがとう。","ENG":"Huh? Yes, I’m okay. Thank you.","TWN":"嗯？ …喔，我沒事，謝謝你。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":"하지만 넌 위험했어! 총을 가진 범죄자를 상대로 그렇게 무모하게 달려들다니!","JPN":"それにしても危ないでしょう！　銃を持った犯罪者を相手に突っ込むなんて！","ENG":"But you! You shouldn’t have gone after a criminal like that, it’s dangerous!","TWN":"但你剛剛那樣很危險！怎麼可以就那樣接近歹徒呢！他手裡有武器欸！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 괜찮습니다. 강화복만 믿고 방심해준 덕에 의외로 쉽게 끝났어요.","JPN":"大丈夫です。強化スーツを過信し、油断してくれたので意外とあっさり終わりました。","ENG":"I’m okay. He was being careless, probably because of the Power Suit he wore.","TWN":"沒事的，他以為有強化服就可以鬆懈，結果讓我可以輕鬆解決掉他。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 그리고 교칙 위반자를 처벌하는 건, 마땅히 선도부의 역할이니까요.","JPN":"それに校則違反者を罰するのは、風紀委員の役目ですから。","ENG":"Plus, I am a student council member. I’m supposed to punish those whose who violate the rules.","TWN":"而且懲處違反校規的人，正是學生會的職責所在。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":"하아… 김초원. 여긴 군대가 아니야. 학교라고. 보통은 그렇게까지 하지 않아도 돼.","JPN":"はあ……ナオさん。ここは軍じゃなくて、学校よ。そこまでしなくていいの。","ENG":"Kim Chowon. This is not the military. We’re in school. You don’t have to do that.","TWN":"哀…金初源，這裡是學校，不是軍隊，你不需要像在當兵一樣。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":"넌 지금 학생이잖아?","JPN":"あなたは今、生徒でしょ？","ENG":"You’re a student now, aren’t you?","TWN":"你現在是學生好嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"선생님의 지시는 이해했습니다.","JPN":"先生の指示、心得ました。","ENG":"I understand your instructions.","TWN":"我明白老師的意思了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"다음부턴 좀 더 학생답게 물렁해지도록 노력해보죠.","JPN":"次からはもっと生徒らしく、怠けるよう努力します。","ENG":"I’ll try to be softer next time.","TWN":"下次我會努力裝得弱一點，才比較像學生。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};